// SDK v0.0.10 bug: WebSocket handler drops AVATAR_SPEAK_TEXT commands
// (logs "Unsupported command event type:" and does nothing).
// Route text commands through LiveKit data channel instead.
const sess = session as Record<string, unknown>;
if (typeof sess.sendCommandEvent === "function") {
  const origSend = (sess.sendCommandEvent as Function).bind(sess);
  sess.sendCommandEvent = (cmd: Record<string, unknown>) => {
    const TEXT_CMDS = ["avatar.speak_text", "avatar.speak_response"];
    const room = sess.room as Record<string, unknown> | undefined;
    if (
      TEXT_CMDS.includes(cmd.event_type as string) &&
      room?.state === "connected"
    ) {
      const data = new TextEncoder().encode(JSON.stringify(cmd));
      const lp = room.localParticipant as Record<string, Function>;
      lp.publishData(data, { reliable: true, topic: "agent-control" });
    } else {
      origSend(cmd);
    }
  };
}

