    >
      {state === "idle" && <IdleView />}
      {state === "loading" && <LoadingView />}
      {state === "showing_outfits" && data && (
        <OutfitsView
          greeting={data.greeting}
          styleAnalysis={data.style_analysis}
          outfits={outfits}
          activeIndex={activeIndex}
          onDotClick={setActiveIndex}
        />
      )}
      {state === "error" && <ErrorView message={errorMsg} />}
    </main>
  );
}

