load_dotenv()

SERPER_SHOPPING_URL = "https://google.serper.dev/shopping"

# Popular brands used as fallback when user has no brand history
POPULAR_BRANDS = [
    "Nike", "Adidas", "Zara", "H&M", "Uniqlo",
    "Levi's", "Ralph Lauren", "Calvin Klein", "Tommy Hilfiger",
