    74→        };
    75→
    76→        this.audioElement.play().catch(err => {
    77→          console.error('Failed to play audio:', err);
    78→          this.speaking = false;
    79→          if (onEnd) onEnd();
    80→          resolve();
    81→        });
    82→      });
    83→
    84→    } catch (err) {
    85→      console.error('ElevenLabs TTS error:', err);
    86→      this.speaking = false;
    87→      if (onEnd) onEnd();
    88→      
    89→      // Fallback to browser TTS
