    91→      return miraTTS.speak(text, onStart, onEnd);
    92→    }
    93→  }
    94→
    95→  stop() {
    96→    if (this.audioElement) {
    97→      this.audioElement.pause();
    98→      this.audioElement = null;
    99→    }
   100→    this.speaking = false;
   101→  }
   102→
