     1→// Speech recognition for voice input
     2→class SpeechInput {
     3→  constructor() {
     4→    // Check for browser support
     5→    const SpeechRecognition = window.SpeechRecognition || window.webkitSpeechRecognition;
     6→    
     7→    if (!SpeechRecognition) {
     8→      console.error('Speech recognition not supported in this browser');
     9→      this.supported = false;
    10→      return;
    11→    }
    12→    
    13→    this.supported = true;
    14→    this.recognition = new SpeechRecognition();
    15→    this.recognition.continuous = false;
    16→    this.recognition.interimResults = true;
    17→    this.recognition.lang = 'en-US';
    18→    
    19→    this.isListening = false;
    20→    this.onResult = null;
    21→    this.onStart = null;
    22→    this.onEnd = null;
    23→    this.onInterim = null;
    24→    
    25→    this.setupHandlers();
    26→  }
    27→
    28→  setupHandlers() {
    29→    if (!this.supported) return;
    30→    
    31→    this.recognition.onstart = () => {
    32→      console.log('Speech recognition started');
    33→      this.isListening = true;
    34→      if (this.onStart) this.onStart();
    35→    };
    36→
    37→    this.recognition.onend = () => {
    38→      console.log('Speech recognition ended');
    39→      this.isListening = false;
    40→      if (this.onEnd) this.onEnd();
    41→    };
    42→
    43→    this.recognition.onerror = (event) => {
    44→      console.error('Speech recognition error:', event.error);
    45→      this.isListening = false;
    46→      if (this.onEnd) this.onEnd();
    47→    };
    48→
    49→    this.recognition.onresult = (event) => {
    50→      let interimTranscript = '';
    51→      let finalTranscript = '';
    52→
    53→      for (let i = event.resultIndex; i < event.results.length; i++) {
    54→        const transcript = event.results[i][0].transcript;
    55→        if (event.results[i].isFinal) {
    56→          finalTranscript += transcript;
    57→        } else {
    58→          interimTranscript += transcript;
    59→        }
    60→      }
    61→
    62→      // Show interim results (what user is saying)
    63→      if (interimTranscript && this.onInterim) {
    64→        this.onInterim(interimTranscript);
    65→      }
    66→
    67→      // Final result
    68→      if (finalTranscript && this.onResult) {
    69→        console.log('Final transcript:', finalTranscript);
    70→        this.onResult(finalTranscript);
    71→      }
    72→    };
    73→  }
    74→
    75→  start() {
    76→    if (!this.supported) {
    77→      console.error('Speech recognition not supported');
    78→      return false;
    79→    }
    80→    
    81→    if (this.isListening) {
    82→      console.log('Already listening');
    83→      return true;
    84→    }
    85→
    86→    try {
    87→      this.recognition.start();
    88→      return true;
    89→    } catch (err) {
    90→      console.error('Failed to start speech recognition:', err);
    91→      return false;
    92→    }
    93→  }
    94→
    95→  stop() {
    96→    if (this.isListening) {
    97→      this.recognition.stop();
    98→    }
    99→  }
   100→}
