    71→function initGemini() {
    72→  if (CONFIG.GEMINI_API_KEY && CONFIG.GEMINI_API_KEY !== 'YOUR_GEMINI_API_KEY') {
    73→    gemini = new GeminiAnalyzer(CONFIG.GEMINI_API_KEY);
    74→    return true;
    75→  }
    76→  return false;
    77→}
