    79→// Find best matching scripted response
    80→function findScriptedResponse(text) {
    81→  const lowerText = text.toLowerCase();
    82→  
    83→  // First, try exact match
    84→  for (const [phrase, data] of Object.entries(SCRIPTED_RESPONSES)) {
    85→    if (lowerText.includes(phrase)) {
    86→      return { phrase, ...data };
    87→    }
    88→  }
    89→  
    90→  // Then, try keyword matching
    91→  let bestMatch = null;
    92→  let bestScore = 0;
    93→  
    94→  for (const [phrase, data] of Object.entries(SCRIPTED_RESPONSES)) {
    95→    let score = 0;
    96→    for (const keyword of data.keywords) {
    97→      if (lowerText.includes(keyword)) {
    98→        score += keyword.length; // longer keyword matches = better
    99→      }
   100→    }
   101→    if (score > bestScore) {
   102→      bestScore = score;
   103→      bestMatch = { phrase, ...data };
   104→    }
   105→  }
   106→  
   107→  // Only return if we have a decent match
   108→  return bestScore >= 4 ? bestMatch : null;
   109→}
   110→
   111→// Get emotion from response for fallback video selection
   112→function detectEmotion(text) {
   113→  const lowerText = text.toLowerCase();
   114→  
   115→  // Check for emotion indicators
   116→  if (/ew|gross|ugly|terrible|awful|yuck|no no|honey/.test(lowerText)) {
   117→    return 'concerned'; // judgmental uses concerned video
   118→  }
   119→  if (/confused|what|why|huh|\?{2,}|don't understand/.test(lowerText)) {
   120→    return 'thinking';
   121→  }
   122→  if (/love|amazing|perfect|yes!|gorgeous|stunning|beautiful|great/.test(lowerText)) {
   123→    return 'excited';
   124→  }
   125→  if (/good|nice|works|not bad|decent|okay|fine/.test(lowerText)) {
   126→    return 'happy';
   127→  }
   128→  if (/hmm|let me|thinking|consider/.test(lowerText)) {
   129→    return 'thinking';
   130→  }
   131→  
   132→  return 'talking'; // default
   133→}
