     1→/**
     2→ * Accumulates streaming text chunks and flushes complete sentences.
     3→ *
     4→ * Sentence boundaries are `.` `!` `?` followed by a space or end-of-input.
     5→ * Handles edge cases: decimal numbers ($29.99), ellipsis (...), empty chunks.
     6→ */
     7→export class SentenceBuffer {
     8→  private buffer = "";
     9→  private onSentence: (sentence: string) => void;
    10→
    11→  constructor(onSentence: (sentence: string) => void) {
    12→    this.onSentence = onSentence;
    13→  }
    14→
    15→  feed(chunk: string): void {
    16→    if (!chunk) return;
    17→    this.buffer += chunk;
    18→    this.drainSentences();
    19→  }
    20→
    21→  flush(): void {
    22→    const text = this.buffer.trim();
    23→    if (text) {
    24→      this.onSentence(text);
    25→    }
    26→    this.buffer = "";
    27→  }
    28→
    29→  private drainSentences(): void {
    30→    // Match sentence-ending punctuation followed by a space.
    31→    // Negative lookbehind avoids splitting on:
    32→    //   - decimal numbers: digit.digit (e.g. $29.99)
    33→    //   - ellipsis: two or more dots (e.g. "hmm...")
    34→    const sentenceEnd = /(?<!\d)(?<!\.)([.!?])\s/g;
    35→    let match: RegExpExecArray | null;
    36→    let lastIndex = 0;
    37→
    38→    while ((match = sentenceEnd.exec(this.buffer)) !== null) {
    39→      // Include the punctuation mark, not the trailing space
    40→      const sentence = this.buffer.slice(lastIndex, match.index + match[1].length).trim();
    41→      if (sentence) {
    42→        this.onSentence(sentence);
    43→      }
    44→      lastIndex = match.index + match[0].length;
    45→    }
    46→
    47→    if (lastIndex > 0) {
    48→      this.buffer = this.buffer.slice(lastIndex);
    49→    }
    50→  }
    51→}
