    11→const API_URL = process.env.NEXT_PUBLIC_API_URL || "http://localhost:8000";
    12→
    13→export interface UseLiveAvatarReturn {
    14→  isReady: boolean;
    15→  isSpeaking: boolean;
    16→  startSession: () => Promise<void>;
    17→  stopSession: () => Promise<void>;
    18→  speak: (text: string) => void;
