     1→"use client";
     2→
     3→import { useCallback, useEffect, useRef, useState } from "react";
     4→import {
     5→  LiveAvatarSession,
     6→  SessionEvent,
     7→  SessionState as AvatarSessionState,
     8→  AgentEventsEnum,
     9→} from "@heygen/liveavatar-web-sdk";
    10→
    11→const API_URL = process.env.NEXT_PUBLIC_API_URL || "http://localhost:8000";
    12→
    13→export interface UseLiveAvatarReturn {
    14→  isReady: boolean;
    15→  isSpeaking: boolean;
    16→  startSession: () => Promise<void>;
    17→  stopSession: () => Promise<void>;
    18→  speak: (text: string) => void;
    19→  interrupt: () => void;
    20→  clearQueue: () => void;
    21→  avatarRef: React.RefObject<HTMLVideoElement | null>;
    22→}
    23→
    24→async function fetchSessionToken(): Promise<string> {
    25→  const res = await fetch(`${API_URL}/api/heygen/token`, {
    26→    method: "POST",
    27→    headers: { "Content-Type": "application/json" },
    28→    body: JSON.stringify({ is_sandbox: true }),
    29→  });
    30→  if (!res.ok) throw new Error(`Failed to fetch LiveAvatar token: ${res.status}`);
    31→  const data = await res.json();
    32→  return data.session_token;
    33→}
    34→
    35→export function useLiveAvatar(): UseLiveAvatarReturn {
    36→  const [isReady, setIsReady] = useState(false);
    37→  const [isSpeaking, setIsSpeaking] = useState(false);
    38→  const avatarRef = useRef<HTMLVideoElement | null>(null);
    39→  const sessionRef = useRef<LiveAvatarSession | null>(null);
    40→  const isReadyRef = useRef(false);
    41→
    42→  // Speech queue — process one sentence at a time to prevent overlapping speech
    43→  const speechQueueRef = useRef<string[]>([]);
    44→  const isProcessingQueueRef = useRef(false);
    45→
    46→  const processQueue = useCallback(() => {
    47→    // Don't attempt repeat() until the session is actually connected
    48→    if (isProcessingQueueRef.current || !sessionRef.current || !isReadyRef.current) return;
    49→
    50→    // SDK fires STREAM_READY before state reaches CONNECTED.
    51→    // repeat() silently no-ops if not CONNECTED, so defer until ready.
    52→    if (sessionRef.current.state !== AvatarSessionState.CONNECTED) {
    53→      setTimeout(() => processQueue(), 200);
    54→      return;
    55→    }
    56→
    57→    const next = speechQueueRef.current.shift();
    58→    if (!next) {
    59→      setIsSpeaking(false);
    60→      return;
    61→    }
    62→    isProcessingQueueRef.current = true;
    63→    setIsSpeaking(true);
    64→    console.log("[LiveAvatar] repeat():", next.slice(0, 60));
    65→    try {
    66→      sessionRef.current.repeat(next);
    67→    } catch (err) {
    68→      console.error("[LiveAvatar] repeat() failed:", err);
    69→      isProcessingQueueRef.current = false;
    70→      // Try next item on next tick instead of leaving queue permanently stuck
    71→      setTimeout(() => processQueue(), 0);
    72→    }
    73→  }, []);
    74→
    75→  const clearQueue = useCallback(() => {
    76→    speechQueueRef.current = [];
    77→    isProcessingQueueRef.current = false;
    78→  }, []);
    79→
    80→  // Cleanup on unmount
    81→  useEffect(() => {
    82→    return () => {
    83→      clearQueue();
    84→      sessionRef.current?.stop().catch(() => {});
    85→      sessionRef.current = null;
    86→      isReadyRef.current = false;
    87→    };
    88→  }, [clearQueue]);
    89→
    90→  const startSession = useCallback(async () => {
    91→    if (sessionRef.current) return;
    92→
    93→    console.log("[LiveAvatar] Fetching session token...");
    94→    const token = await fetchSessionToken();
    95→    console.log("[LiveAvatar] Token received, creating session...");
    96→    const session = new LiveAvatarSession(token);
    97→    sessionRef.current = session;
    98→
    99→    session.on(SessionEvent.SESSION_STREAM_READY, () => {
   100→      console.log("[LiveAvatar] Stream ready — attaching video + draining queue");
   101→      if (avatarRef.current) {
   102→        session.attach(avatarRef.current);
   103→      }
   104→      isReadyRef.current = true;
   105→      setIsReady(true);
   106→      // Drain any speech that queued while we were connecting
   107→      processQueue();
   108→    });
   109→
   110→    session.on(AgentEventsEnum.AVATAR_SPEAK_STARTED, () => {
   111→      console.log("[LiveAvatar] Avatar started speaking");
   112→      setIsSpeaking(true);
   113→    });
   114→
   115→    session.on(AgentEventsEnum.AVATAR_SPEAK_ENDED, () => {
   116→      console.log("[LiveAvatar] Avatar stopped speaking, processing next in queue");
   117→      isProcessingQueueRef.current = false;
   118→      processQueue();
   119→    });
   120→
   121→    session.on(SessionEvent.SESSION_DISCONNECTED, (reason) => {
   122→      console.log("[LiveAvatar] Disconnected:", reason);
   123→      isReadyRef.current = false;
   124→      setIsReady(false);
   125→      setIsSpeaking(false);
   126→      clearQueue();
   127→      sessionRef.current = null;
   128→    });
   129→
   130→    session.on(SessionEvent.SESSION_STATE_CHANGED, (state: AvatarSessionState) => {
   131→      console.log("[LiveAvatar] State changed:", state);
   132→    });
   133→
   134→    console.log("[LiveAvatar] Starting session...");
   135→    try {
   136→      await session.start();
   137→    } catch (err) {
   138→      console.error("[LiveAvatar] session.start() failed:", err);
   139→      sessionRef.current = null;
   140→      throw err;
   141→    }
   142→    console.log("[LiveAvatar] session.start() resolved");
   143→
   144→    // SDK v0.0.10 bug: WebSocket handler drops AVATAR_SPEAK_TEXT commands
   145→    // (logs "Unsupported command event type:" and does nothing).
   146→    // Route text commands through LiveKit data channel instead.
   147→    // eslint-disable-next-line @typescript-eslint/no-explicit-any
   148→    const sess = session as any;
   149→    if (typeof sess.sendCommandEvent === "function") {
   150→      const origSend = sess.sendCommandEvent.bind(sess);
   151→      sess.sendCommandEvent = (cmd: any) => {
   152→        const TEXT_CMDS = ["avatar.speak_text", "avatar.speak_response"];
   153→        if (
   154→          TEXT_CMDS.includes(cmd.event_type) &&
   155→          sess.room?.state === "connected"
   156→        ) {
   157→          const data = new TextEncoder().encode(JSON.stringify(cmd));
   158→          sess.room.localParticipant.publishData(data, {
   159→            reliable: true,
   160→            topic: "agent-control",
   161→          });
   162→        } else {
   163→          origSend(cmd);
   164→        }
   165→      };
   166→    }
   167→  }, [processQueue, clearQueue]);
   168→
   169→  const stopSession = useCallback(async () => {
   170→    if (!sessionRef.current) return;
   171→    clearQueue();
   172→    isReadyRef.current = false;
   173→    await sessionRef.current.stop();
   174→    sessionRef.current = null;
   175→    setIsReady(false);
   176→    setIsSpeaking(false);
   177→  }, [clearQueue]);
   178→
   179→  const speak = useCallback(
   180→    (text: string) => {
   181→      if (!text.trim()) return;
   182→      console.log("[LiveAvatar] Queued:", text.slice(0, 60), `(ready=${isReadyRef.current}, queue=${speechQueueRef.current.length})`);
   183→      speechQueueRef.current.push(text);
   184→      setIsSpeaking(true);
   185→      processQueue();
   186→    },
   187→    [processQueue],
   188→  );
   189→
   190→  const interrupt = useCallback(() => {
   191→    if (!sessionRef.current) return;
   192→    clearQueue();
   193→    sessionRef.current.interrupt();
   194→  }, [clearQueue]);
   195→
   196→  return {
   197→    isReady,
   198→    isSpeaking,
   199→    startSession,
   200→    stopSession,
   201→    speak,
   202→    interrupt,
   203→    clearQueue,
   204→    avatarRef,
   205→  };
   206→}
