     1→// ElevenLabs TTS for high-quality voice
     2→class ElevenLabsTTS {
     3→  constructor(apiKey, voiceId) {
     4→    this.apiKey = apiKey;
     5→    this.voiceId = voiceId || 'EXAVITQu4vr4xnSDxMaL'; // Default: Sarah (warm female)
     6→    this.baseUrl = 'https://api.elevenlabs.io/v1';
     7→    this.speaking = false;
     8→    this.audioElement = null;
     9→  }
    10→
    11→  setVoice(voiceId) {
    12→    this.voiceId = voiceId;
    13→  }
    14→
    15→  async speak(text, onStart, onEnd) {
    16→    if (!this.apiKey) {
    17→      console.error('ElevenLabs API key not set');
    18→      // Fallback to browser TTS
    19→      return miraTTS.speak(text, onStart, onEnd);
    20→    }
    21→
    22→    try {
    23→      this.speaking = true;
    24→      if (onStart) onStart();
    25→
    26→      // Call ElevenLabs API
    27→      const response = await fetch(
    28→        `${this.baseUrl}/text-to-speech/${this.voiceId}`,
    29→        {
    30→          method: 'POST',
    31→          headers: {
    32→            'Accept': 'audio/mpeg',
    33→            'Content-Type': 'application/json',
    34→            'xi-api-key': this.apiKey
    35→          },
    36→          body: JSON.stringify({
    37→            text: text,
    38→            model_id: 'eleven_multilingual_v2',
    39→            voice_settings: {
    40→              stability: 0.5,
    41→              similarity_boost: 0.8,
    42→              style: 0.5,
    43→              use_speaker_boost: true
    44→            }
    45→          })
    46→        }
    47→      );
    48→
    49→      if (!response.ok) {
    50→        const error = await response.json();
    51→        throw new Error(error.detail?.message || 'ElevenLabs API error');
    52→      }
    53→
    54→      // Get audio blob
    55→      const audioBlob = await response.blob();
    56→      const audioUrl = URL.createObjectURL(audioBlob);
    57→
    58→      // Play audio
    59→      return new Promise((resolve) => {
    60→        this.audioElement = new Audio(audioUrl);
    61→        
    62→        this.audioElement.onended = () => {
    63→          this.speaking = false;
    64→          URL.revokeObjectURL(audioUrl);
    65→          if (onEnd) onEnd();
    66→          resolve();
    67→        };
    68→
    69→        this.audioElement.onerror = (err) => {
    70→          console.error('Audio playback error:', err);
    71→          this.speaking = false;
    72→          if (onEnd) onEnd();
    73→          resolve();
    74→        };
    75→
    76→        this.audioElement.play().catch(err => {
    77→          console.error('Failed to play audio:', err);
    78→          this.speaking = false;
    79→          if (onEnd) onEnd();
    80→          resolve();
    81→        });
    82→      });
    83→
    84→    } catch (err) {
    85→      console.error('ElevenLabs TTS error:', err);
    86→      this.speaking = false;
    87→      if (onEnd) onEnd();
    88→      
    89→      // Fallback to browser TTS
    90→      console.log('Falling back to browser TTS...');
    91→      return miraTTS.speak(text, onStart, onEnd);
    92→    }
    93→  }
    94→
    95→  stop() {
    96→    if (this.audioElement) {
    97→      this.audioElement.pause();
    98→      this.audioElement = null;
    99→    }
   100→    this.speaking = false;
   101→  }
   102→
   103→  isSpeaking() {
   104→    return this.speaking;
   105→  }
   106→
   107→  // List available voices (for debugging)
   108→  async listVoices() {
   109→    if (!this.apiKey) return [];
   110→    
   111→    const response = await fetch(`${this.baseUrl}/voices`, {
   112→      headers: { 'xi-api-key': this.apiKey }
