   114→    
   115→    if (response.ok) {
   116→      const data = await response.json();
   117→      return data.voices;
   118→    }
   119→    return [];
   120→  }
   121→}
   122→
   123→// Will be initialized in config if API key is provided
   124→let elevenLabsTTS = null;
   125→
   126→function initElevenLabs() {
   127→  if (CONFIG.ELEVENLABS_API_KEY && CONFIG.ELEVENLABS_API_KEY !== 'YOUR_ELEVENLABS_API_KEY') {
   128→    elevenLabsTTS = new ElevenLabsTTS(CONFIG.ELEVENLABS_API_KEY, CONFIG.ELEVENLABS_VOICE_ID);
   129→    console.log('ElevenLabs TTS initialized');
   130→    return true;
   131→  }
   132→  return false;
   133→}
   134→
   135→// Smart TTS function that uses ElevenLabs if available, otherwise browser TTS
   136→async function smartSpeak(text, onStart, onEnd) {
   137→  if (elevenLabsTTS) {
   138→    return elevenLabsTTS.speak(text, onStart, onEnd);
   139→  } else {
   140→    return miraTTS.speak(text, onStart, onEnd);
