     1→// Text-to-speech for Mira's voice
     2→class MiraTTS {
     3→  constructor() {
     4→    this.synth = window.speechSynthesis;
     5→    this.voice = null;
     6→    this.speaking = false;
     7→    this.ready = false;
     8→    this.initVoice();
     9→  }
    10→
    11→  initVoice() {
    12→    const setVoice = () => {
    13→      const voices = this.synth.getVoices();
    14→      if (voices.length === 0) {
    15→        console.log('No voices available yet...');
    16→        return;
    17→      }
    18→      
    19→      // Try to find a nice female voice
    20→      this.voice = voices.find(v => 
    21→        v.name.includes('Samantha') || 
    22→        v.name.includes('Karen') ||
    23→        v.name.includes('Moira') ||
    24→        v.name.includes('Google US English Female') ||
    25→        v.name.includes('Microsoft Zira')
    26→      ) || voices.find(v => 
    27→        v.lang.startsWith('en') && v.name.toLowerCase().includes('female')
    28→      ) || voices.find(v => 
    29→        v.lang.startsWith('en-US')
    30→      ) || voices.find(v => 
    31→        v.lang.startsWith('en')
    32→      ) || voices[0];
    33→      
    34→      this.ready = true;
    35→      console.log('TTS ready, using voice:', this.voice?.name);
    36→    };
    37→
    38→    // Try immediately
    39→    setVoice();
    40→    
    41→    // Also listen for voices changed (some browsers load async)
    42→    this.synth.addEventListener('voiceschanged', setVoice);
    43→    
    44→    // Force load on some browsers
    45→    setTimeout(() => {
    46→      if (!this.ready) setVoice();
    47→    }, 100);
    48→  }
    49→
    50→  async speak(text, onStart, onEnd) {
    51→    return new Promise((resolve) => {
    52→      if (!CONFIG.TTS_ENABLED) {
    53→        console.log('TTS disabled');
    54→        if (onStart) onStart();
    55→        setTimeout(() => {
    56→          if (onEnd) onEnd();
    57→          resolve();
    58→        }, text.length * 50); // Fake duration
    59→        return;
    60→      }
    61→
    62→      if (!this.synth) {
    63→        console.error('Speech synthesis not supported');
    64→        resolve();
    65→        return;
    66→      }
    67→
    68→      // Cancel any ongoing speech
    69→      this.synth.cancel();
    70→      
    71→      // Wait for ready
    72→      if (!this.ready) {
    73→        console.log('Waiting for TTS to be ready...');
    74→        setTimeout(() => this.speak(text, onStart, onEnd).then(resolve), 200);
    75→        return;
    76→      }
    77→
    78→      const utterance = new SpeechSynthesisUtterance(text);
    79→      
    80→      if (this.voice) {
    81→        utterance.voice = this.voice;
    82→      }
    83→      
    84→      utterance.rate = 1.0;
    85→      utterance.pitch = 1.1;
    86→      utterance.volume = 1.0;
    87→
    88→      utterance.onstart = () => {
    89→        console.log('TTS started');
    90→        this.speaking = true;
    91→        if (onStart) onStart();
    92→      };
    93→
    94→      utterance.onend = () => {
    95→        console.log('TTS ended');
    96→        this.speaking = false;
    97→        if (onEnd) onEnd();
    98→        resolve();
    99→      };
   100→
   101→      utterance.onerror = (err) => {
   102→        console.error('TTS error:', err);
   103→        this.speaking = false;
   104→        if (onEnd) onEnd();
   105→        resolve();
   106→      };
   107→
   108→      // Chrome bug workaround - need to resume if paused
   109→      if (this.synth.paused) {
   110→        this.synth.resume();
   111→      }
   112→
   113→      console.log('Speaking:', text.substring(0, 50) + '...');
   114→      this.synth.speak(utterance);
   115→      
   116→      // Chrome bug: sometimes onend doesn't fire
   117→      // Set a timeout based on text length as fallback
   118→      const timeout = Math.max(5000, text.length * 80);
   119→      setTimeout(() => {
   120→        if (this.speaking) {
   121→          console.log('TTS timeout fallback');
   122→          this.speaking = false;
   123→          if (onEnd) onEnd();
   124→          resolve();
   125→        }
   126→      }, timeout);
   127→    });
   128→  }
   129→
   130→  stop() {
   131→    this.synth.cancel();
   132→    this.speaking = false;
   133→  }
   134→
   135→  isSpeaking() {
   136→    return this.speaking;
   137→  }
   138→  
   139→  // Test TTS with a short phrase (call on user gesture)
   140→  test() {
   141→    return this.speak("Hey there!");
   142→  }
   143→}
   144→
   145→const miraTTS = new MiraTTS();
   146→

