     1→// Avatar state management with video loops
     2→class MiraAvatar {
     3→  constructor() {
     4→    this.container = document.getElementById('mira-avatar-container');
     5→    this.stateIndicator = document.getElementById('state-indicator');
     6→    this.currentState = 'idle';
     7→    this.videos = {};
     8→    this.currentVideo = null;
     9→    this.scriptedVideo = null; // For one-shot scripted videos
    10→    this.initialized = false;
    11→  }
    12→
    13→  async init() {
    14→    // Create video elements for each state (looping videos)
    15→    const states = ['idle', 'thinking', 'happy', 'excited', 'talking', 'concerned'];
    16→    
    17→    for (const state of states) {
    18→      const video = document.createElement('video');
    19→      video.id = `video-${state}`;
    20→      video.className = 'avatar-video';
    21→      video.loop = true;
    22→      video.muted = true;
    23→      video.playsInline = true;
    24→      video.preload = 'auto';
    25→      
    26→      // Set source based on config
    27→      const src = CONFIG.AVATAR_VIDEOS?.[state] || `assets/videos/${state}.mp4`;
    28→      video.src = src;
    29→      
    30→      // Hide all videos initially
    31→      video.style.display = 'none';
    32→      
    33→      this.container.appendChild(video);
    34→      this.videos[state] = video;
    35→      
    36→      // Preload
    37→      video.load();
    38→    }
    39→    
    40→    // Create a single video element for scripted responses (with audio)
    41→    this.scriptedVideo = document.createElement('video');
    42→    this.scriptedVideo.id = 'video-scripted';
    43→    this.scriptedVideo.className = 'avatar-video';
    44→    this.scriptedVideo.loop = false; // One-shot, not looping
    45→    this.scriptedVideo.muted = false; // Has audio!
    46→    this.scriptedVideo.playsInline = true;
    47→    this.scriptedVideo.preload = 'auto';
    48→    this.scriptedVideo.style.display = 'none';
    49→    this.container.appendChild(this.scriptedVideo);
    50→    
    51→    // When scripted video ends, return to idle
    52→    this.scriptedVideo.addEventListener('ended', () => {
    53→      this.scriptedVideo.style.display = 'none';
    54→      this.idle();
    55→    });
    56→    
    57→    // Show idle by default
    58→    this.setState('idle');
    59→    this.initialized = true;
    60→    console.log('Avatar videos initialized');
    61→  }
    62→
    63→  setState(state) {
    64→    if (!this.videos[state]) {
    65→      console.warn(`Unknown avatar state: ${state}`);
    66→      return;
    67→    }
    68→    
    69→    // Hide scripted video if playing
    70→    if (this.scriptedVideo) {
    71→      this.scriptedVideo.pause();
    72→      this.scriptedVideo.style.display = 'none';
    73→    }
    74→    
    75→    // Hide current looping video
    76→    if (this.currentVideo) {
    77→      this.currentVideo.pause();
    78→      this.currentVideo.style.display = 'none';
    79→    }
    80→    
    81→    // Show and play new looping video
    82→    this.currentVideo = this.videos[state];
    83→    this.currentVideo.style.display = 'block';
    84→    this.currentVideo.currentTime = 0;
    85→    this.currentVideo.play().catch(err => {
    86→      console.warn('Video autoplay failed:', err);
    87→    });
    88→    
    89→    // Update indicator
    90→    if (this.stateIndicator) {
    91→      this.stateIndicator.textContent = state.toUpperCase();
    92→    }
    93→    this.currentState = state;
    94→  }
    95→
    96→  // Play a scripted video with baked-in audio (one-shot)
    97→  async playScriptedVideo(videoPath) {
    98→    return new Promise((resolve) => {
    99→      // Hide current looping video
   100→      if (this.currentVideo) {
   101→        this.currentVideo.pause();
   102→        this.currentVideo.style.display = 'none';
   103→      }
   104→      
   105→      // Set up scripted video
   106→      this.scriptedVideo.src = videoPath;
   107→      this.scriptedVideo.style.display = 'block';
   108→      
   109→      // Update indicator
   110→      if (this.stateIndicator) {
   111→        this.stateIndicator.textContent = 'SCRIPTED';
   112→      }
   113→      
   114→      // Resolve when video ends
   115→      const onEnded = () => {
   116→        this.scriptedVideo.removeEventListener('ended', onEnded);
   117→        resolve();
   118→      };
   119→      this.scriptedVideo.addEventListener('ended', onEnded);
   120→      
   121→      // Also resolve on error
   122→      const onError = () => {
   123→        console.warn('Scripted video failed to play');
   124→        this.scriptedVideo.removeEventListener('error', onError);
   125→        this.idle();
   126→        resolve();
   127→      };
   128→      this.scriptedVideo.addEventListener('error', onError, { once: true });
   129→      
   130→      // Play with audio
   131→      this.scriptedVideo.play().catch(err => {
   132→        console.warn('Scripted video autoplay failed:', err);
   133→        this.idle();
   134→        resolve();
   135→      });
   136→    });
   137→  }
   138→
   139→  idle() {
   140→    this.setState('idle');
   141→  }
   142→
   143→  thinking() {
   144→    this.setState('thinking');
   145→  }
   146→
   147→  talking() {
   148→    this.setState('talking');
   149→  }
   150→
   151→  happy() {
   152→    this.setState('happy');
   153→    // Stay happy for a bit then return to idle
   154→    setTimeout(() => {
   155→      if (this.currentState === 'happy') this.idle();
   156→    }, 5000);
   157→  }
   158→
   159→  excited() {
   160→    this.setState('excited');
   161→    setTimeout(() => {
